def solve(arg1: dict) -> dict:
    if 'name' not in arg1 or not arg1['name']:
        return {'error': 'Project name is required.'}

    # Simulating a project creation
    project_id = '1'  # This would be generated by the database in a real scenario
    project = {
        'id': project_id,
        'name': arg1['name'],
        'description': arg1.get('description', ''),
        'status': arg1.get('status', 'active')
    }

    # Simulating a check for duplicate project names
    existing_projects = [{'name': 'Existing Project'}]  # This would be fetched from the database
    if any(p['name'] == project['name'] for p in existing_projects):
        return {'error': 'Project with this name already exists.'}

    return project
